example.code:
type User {
  id: ID!
  name: String!
  email: String!
  orders: [Order!]!
  createdAt: DateTime!
}

type Query {
  user(id: ID!): User
  users(first: Int, after: String): UserConnection!
}

type Mutation {
  createUser(input: CreateUserInput!): User!
  updateUser(id: ID!, input: UpdateUserInput!): User!
  deleteUser(id: ID!): Boolean!
}

type Subscription {
  orderStatusChanged(userId: ID!): Order!
}

input CreateUserInput {
  name: String!
  email: String!
}

type UserConnection {
  edges: [UserEdge!]!
  pageInfo: PageInfo!
  totalCount: Int!
}

type UserEdge {
  cursor: String!
  node: User!
}

type PageInfo {
  hasNextPage: Boolean!
  hasPreviousPage: Boolean!
  startCursor: String
  endCursor: String
}

# Users subgraph (owner)
type User @key(fields: "id") {
  id: ID!
  name: String!
  email: String!
}

# Orders subgraph (consumer)
extend type User @key(fields: "id") {
  id: ID! @external
  orders: [Order!]!
}

import DataLoader from 'dataloader';

// Instantiate per-request in context factory
const userLoader = new DataLoader(async (userIds: readonly string[]) => {
  const users = await db.users.findMany({ where: { id: { in: [...userIds] } } });
  return userIds.map(id => users.find(u => u.id === id) ?? null);
});

// In resolver
const resolve = (order: Order) => userLoader.load(order.userId);

// Module-global DataLoader — cross-request cache leak
const globalUserLoader = new DataLoader(async (ids) => {
  return db.users.findMany({ where: { id: { in: [...ids] } } });
});
